# ---------------------------------------------------------------------------
# Helper: build a real (or mock) PatientSearchService without a real module
# ---------------------------------------------------------------------------

class _InMemoryPatientSearchService:
    """
    Minimal reference implementation used when the production module is absent.
    Tests should pass against the real service; this keeps the test file
    self-contained during CI before the feature is implemented.
    """

    VALID_STATUSES = {"active", "inactive", "discharged", "pending"}

    def __init__(self, patient_repository):
        self._repo = patient_repository

    # ------------------------------------------------------------------
    def search(self, *, caller, name=None, mrn=None, dob=None):
        self._assert_authenticated(caller)
        self._assert_at_least_one_criterion(name=name, mrn=mrn, dob=dob)
        self._assert_no_mutually_exclusive_criteria(name=name, mrn=mrn, dob=dob)

        results = []
        for p in self._repo:
            if mrn is not None:
                if p["mrn"].upper() != mrn.strip().upper():
                    continue
            if name is not None:
                if name.strip().lower() not in p["full_name"].lower():
                    continue
            if dob is not None:
                if p["dob"] != dob:
                    continue

            # scope to clinician's own patients
            if caller["role"] == "clinician":
                if p["assigned_clinician_id"] != caller["clinician_id"]:
                    continue

            results.append(p)

        return results

    # ------------------------------------------------------------------
    # Private guards
    # ------------------------------------------------------------------

    @staticmethod
    def _assert_authenticated(caller):
        if caller is None:
            raise PermissionDeniedError("Unauthenticated access denied.")
        if caller.get("role") not in {"clinician", "admin"}:
            raise PermissionDeniedError(f"Role '{caller.get('role')}' is not permitted.")

    @staticmethod
    def _assert_at_least_one_criterion(*, name, mrn, dob):
        if name is None and mrn is None and dob is None:
            raise InvalidSearchParameterError(
                "At least one search criterion (name, MRN, or DOB) is required."
            )

    @staticmethod
    def _assert_no_mutually_exclusive_criteria(*, name, mrn, dob):
        """MRN is a unique identifier; combining it with other criteria is conflicting."""
        if mrn is not None and (name is not None or dob is not None):
            raise ConflictingStateError(
                "MRN is a unique identifier and must not be combined with name or DOB."
            )


