class TestSearchByName:
    """Clinician searches patients by full or partial name."""

    def test_exact_full_name_returns_own_patient(self, svc, clinician_a):
        results = svc.search(caller=clinician_a, name="Alice Wonderland")
        assert len(results) == 1
        assert results[0]["patient_id"] == "P-001"

    def test_partial_first_name_returns_only_own_patients(self, svc, clinician_a):
        # clinician_a has "Alice Wonderland"; clinician_b has "Alice Cooper"
        results = svc.search(caller=clinician_a, name="Alice")
        ids = {r["patient_id"] for r in results}
        assert "P-001" in ids, "Expected own patient Alice Wonderland"
        assert "P-005" not in ids, "Must not return another clinician's patient"

    def test_partial_last_name_match(self, svc, clinician_a):
        results = svc.search(caller=clinician_a, name="Build")
        assert any(r["patient_id"] == "P-002" for r in results)

    def test_name_search_is_case_insensitive(self, svc, clinician_a):
        results_lower = svc.search(caller=clinician_a, name="alice wonderland")
        results_upper = svc.search(caller=clinician_a, name="ALICE WONDERLAND")
        assert results_lower == results_upper

    def test_name_search_trims_whitespace(self, svc, clinician_a):
        results = svc.search(caller=clinician_a, name="  Alice  ")
        assert any(r["patient_id"] == "P-001" for r in results)

    def test_name_no_match_returns_empty_list(self, svc, clinician_a):
        results = svc.search(caller=clinician_a, name="Nonexistent Patient")
        assert results == []

    def test_clinician_cannot_see_other_clinicians_patients_by_name(
        self, svc, clinician_a, clinician_b
    ):
        # "Diana Prince" belongs to clinician_b
        results = svc.search(caller=clinician_a, name="Diana Prince")
        assert results == []

    def test_discharged_patient_still_searchable_by_name(self, svc, clinician_a):
        """Discharged patients remain accessible; status filtering is a separate concern."""
        results = svc.search(caller=clinician_a, name="Charlie Brown")
        assert any(r["patient_id"] == "P-003" for r in results)


