class TestClinicalScope:
    """Ensure results are scoped only to the calling clinician's patients."""

    def test_clinician_a_results_never_contain_clinician_b_patients(
        self, svc, clinician_a, patient_repo
    ):
        clinician_b_ids = {
            p["patient_id"]
            for p in patient_repo
            if p["assigned_clinician_id"] == "CLN-002"
        }
        results = svc.search(caller=clinician_a, name="")  # empty name → should raise
        # This assertion path would only be reached if search does not raise;
        # kept here as a safety net for incorrect implementations.
        for r in results:
            assert r["patient_id"] not in clinician_b_ids

    def test_two_clinicians_see_disjoint_results_for_same_name(
        self, svc, clinician_a, clinician_b
    ):
        results_a = svc.search(caller=clinician_a, name="Alice")
        results_b = svc.search(caller=clinician_b, name="Alice")

        ids_a = {r["patient_id"] for r in results_a}
        ids_b = {r["patient_id"] for r in results_b}

        # No overlap
        assert ids_a.isdisjoint(ids_b), (
            "Clinicians must not share search result sets for the same query"
        )
        # Each sees only their own patient named Alice
        assert "P-001" in ids_a  # Alice Wonderland → clinician_a
        assert "P-005" in ids_b  # Alice Cooper     → clinician_b


