class TestConflictingStateTransitions:
    """
    Negative path: search requests that combine mutually exclusive
    criteria or are issued during an inconsistent system state.
    """

    def test_mrn_and_name_combined_raises_conflicting_state(self, svc, clinician_a):
        with pytest.raises(ConflictingStateError):
            svc.search(caller=clinician_a, mrn="MRN-AAA111", name="Alice")

    def test_mrn_and_dob_combined_raises_conflicting_state(self, svc, clinician_a):
        with pytest.raises(ConflictingStateError):
            svc.search(caller=clinician_a, mrn="MRN-AAA111", dob=date(1990, 3, 22))

    def test_mrn_and_name_and_dob_combined_raises_conflicting_state(
        self, svc, clinician_a
    ):
        with pytest.raises(ConflictingStateError):
            svc.search(
                caller=clinician_a,
                mrn="MRN-AAA111",
                name="Alice",
                dob=date(1990, 3, 22),
            )

    def test_search_during_maintenance_window_raises_conflicting_state(
        self, svc, clinician_a
    ):
        """
        System is in maintenance mode — all search operations must be rejected
        to prevent partial or inconsistent data from being surfaced.
        """
        with patch.object(
            type(svc), "maintenance_mode", new_callable=PropertyMock, return_value=True
        ):
            with pytest.raises((ConflictingStateError, PermissionDeniedError)):
                svc.search(caller=clinician_a, name="Alice")

    def test_search_while_patient_record_locked_raises_conflicting_state(
        self, svc, clinician_a, patient_repo
    ):
        """
        A patient record exclusively locked (e.g., during concurrent edit)
        must not be surfaced in search results; raising ConflictingStateError
        signals that the caller should retry.
        """
        with patch.object(svc, "_is_record_locked", return_value=True):
            with pytest.raises(ConflictingStateError):
                svc.search(caller=clinician_a, mrn="MRN-AAA111")

    def test_patient_transferred_mid_search_returns_no_results(
        self, svc, clinician_a, patient_repo
    ):
        """
        If a patient is transferred to another clinician between the
        authentication check and the result assembly, the original
        clinician must not receive the record.
        """

        def _transfer_during_search(*args, **kwargs):
            # Mutate the repo to simulate concurrent transfer
            for p in patient_repo:
                if p["patient_id"] == "P-001":
                    p["assigned_clinician_id"] = "CLN-002"
            return []  # transferred patient must not be in results

        with patch.object(svc, "search", side_effect=_transfer_during_search):
            results = svc.search(caller=clinician_a, name="Alice Wonderland")
            assert results == []

    def test_duplicate_mrn_in_repository_raises_ambiguous_search_error(
        self, svc, patient_repo, clinician_a
    ):
        """Data-integrity violation: two patients with the same MRN."""
        patient_repo.append(
            {
                "patient_id": "P-DUP",
                "first_name": "Duplicate",
                "last_name": "Patient",
                "full_name": "Duplicate Patient",
                "mrn": "MRN-AAA111",  # intentional duplicate
                "dob": date(1992, 5, 10),
                "status": "active",
                "assigned_clinician_id": clinician_a["clinician_id"],
            }
        )
        with pytest.raises((AmbiguousSearchError, ConflictingStateError)):
            svc.search(caller=clinician_a, mrn="MRN-AAA111")


class TestAuditAndLogging:
    """
    Non-functional requirement: every search — successful or failed —
    must produce an audit log entry.
    """

    def test_successful_search_emits_audit_event(self, svc, clinician_a):
        with patch.object(svc, "_emit_audit_event") as mock_audit:
            svc.search(caller=clinician_a, name="Alice")
            mock_audit.assert_called_once()
            call_kwargs = mock_audit.call_args[1] or {}
            call_args = mock_audit.call_args[0]
            audit_payload = call_kwargs or (call_args[0] if call_args else {})
            assert audit_payload.get("outcome") in {None, "success", "SUCCESS"}

    def test_failed_search_permission_denied_emits_audit_event(
        self, svc, unauthenticated_user
    ):
        with patch.object(svc, "_emit_audit_event") as mock_audit:
            with pytest.raises(PermissionDeniedError):
                svc.search(caller=unauthenticated_user, name="Alice")
            mock_audit.assert_called_once()

    def test_audit_event_contains_clinician_id(self, svc, clinician_a):
        with patch.object(svc, "_emit_audit_event") as mock_audit:
            svc.search(caller=clinician_a, name="Alice")
            call_args = mock_audit.call_args
            # Accept positional or keyword argument
            payload = (
                call_args[1]
                if call_args[1]
                else (call_args[0][0] if call_args[0] else {})
            )
            assert payload.get("clinician_id") == clinician_a["clinician_id"]


