        assert len(results) <= 100  # system-defined maximum


class TestResponseShape:
    """Validate the structure of returned patient records."""

    REQUIRED_FIELDS = {"patient_id", "first_name", "last_name", "mrn", "dob", "status"}

    def test_result_contains_required_fields(self, svc, clinician_a):
        results = svc.search(caller=clinician_a, name="Alice Wonderland")
        assert results, "Expected at least one result"
        for field in self.REQUIRED_FIELDS:
            assert field in results[0], f"Missing required field: {field}"

    def test_result_does_not_expose_other_clinician_id(self, svc, clinician_a):
        results = svc.search(caller=clinician_a, name="Alice Wonderland")
        for r in results:
            # The other clinician's ID must not leak into the payload
            assert r.get("assigned_clinician_id") != "CLN-002"

    def test_dob_returned_as_date_type(self, svc, clinician_a):
        results = svc.search(caller=clinician_a, mrn="MRN-AAA111")
        assert isinstance(results[0]["dob"], date)

